var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"최근 영화 산업은 한 신예 감독의 작품에 주목하고 있다.","JPN":"最近の映画産業は、とある新鋭監督の作品に注目している。","ENG":"Recently, the film industry is taking notice of a work of a rookie director.","TWN":"最近在電影界，有一位新銳導演的作品相當受到矚目。"},"stage":{"bg":"FALLEN_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 영화는 흔한 개성의 작가주의가 만연하던 영화계에 참신한 충격을 선사했다.","JPN":"この映画は、ありふれた個性の作家主義が蔓延していた映画界に新鮮な衝撃を与えた。","ENG":"The movie was a fresh shock to the auteurism prevalent film industry.","TWN":"這部電影跳脫制式的框架，為電影界注入一股嶄新的氛圍。"},"stage":{"bg":"FALLEN_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"세계적인 드라마, 유혹의 함교 리허설 세트에서 벌어진 사건을 담아낸 이 영화는 싸구려 캠코더 한 대로 전부 촬영한 것 같은 올드 스타일의 다큐멘터리 기법을 사용하고 있다.","JPN":"グローバルなドラマ、誘惑の艦橋のリハーサルセットで発生した事件を収録したこの映画は、安物のビデオカメラ1台で全て撮影したようなオールドスタイルのドキュメンタリー制作手法を使用している。","ENG":"Filmed on the set of the popular TV series \\"The Bridge of Seduction\\", this movie uses an old-style documentary technique as if it has been filmed entirely with a cheap camcorder.","TWN":"戲裡在講述全球知名連續劇 誘惑的艦橋，在排演時發生的事件，全程只使用一台便宜的攝影機，以懷舊的紀錄片手法拍攝而成。"},"stage":{"bg":"FALLEN_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"인공적인 첨가물이 전혀 느껴지지 않는 리얼한 전투 CG와 카메라 뒤편에서 벌어지는 배우 후보들 간의 경쟁은 물질만능이라는 다소 직설적인 주제의식으로 많은 평론가들의 고개를 끄덕이게 만든다.","JPN":"人工的な作り物感がまったく感じられないリアルな戦闘CGと、カメラの裏で繰り広げられる女優候補たちの争いは、物質万能という多少直接的なテーマで多くの評論家たちをうなずかせる。","ENG":"The realistic CGI in battle and rivalry between the candidates behind the scenes all portray a theme of materialism and are enough to make critics hand out good marks.","TWN":"沒有任何後製處理的真實戰鬥CG，和鏡頭外演員之間的明爭暗鬥，皆受到許多影評的好評。"},"stage":{"bg":"FALLEN_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"영화와 다큐멘터리, 연기와 현실의 교묘한 간극, 늑대인간과 뱀파이어!","JPN":"映画とドキュメンタリー、演技と現実の絶妙な狭間、ライカンスロープとヴァンパイア！","ENG":"The slight rift between Movie and documentary, and acting and reality. Lycanthrope and Vampire!","TWN":"電影和紀錄片、演戲和現實之前巧妙的結合，還有狼人和吸血鬼！"},"stage":{"bg":"FALLEN_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"이 모든 것이 한 작가의 머릿속에서 나왔다고는 믿기 힘든…","JPN":"このすべてが作家1人の頭の中で生まれたとは信じられないほどの……","ENG":"It’s hard to believe that a single person thought of the whole plot...","TWN":"沒想到這些題材，全是從一位編劇的腦袋裡蹦出來的…"},"stage":{"bg":"FALLEN_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"멋지군요. 이번 출품작에 대한 기사들이 하나 같이 호평일색으로 가득합니다, 주인님.","JPN":"素晴らしい。今回の出品作についての記事が全部大好評です、ご主人様。","ENG":"Splendid. The articles about your entry are full of compliments, Mistress.","TWN":"主人好厲害！這次的作品受到新聞一致的好評呢！"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"처음부터 이 모든 상황을 카메라로 찍을 계획이셨던 건가요?","JPN":"最初からこのすべての状況をカメラに収めるつもりだったのですか？","ENG":"Did you plan to film the whole situation from the beginning?","TWN":"您從一開始就計畫要把這一切都拍下來嗎？"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"그래, 그 의뢰인이 찾아올 때부터 재미있는 사건의 냄새가 풍기더구나.","JPN":"ああ、あの依頼人が来た時から面白い事件のニオイがしたのじゃ。","ENG":"Yes, I sensed this was going to be a fun event when that client visited us.","TWN":"沒錯，那個委託人上門時，我就聞到一股有趣的味道。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"그 옹졸한 자존심을 적당히 자극했더니 꽤나 괜찮은 그림이 나왔지.","JPN":"あの卑劣なプライドを適当に刺激したら、なかなか良い絵が撮れた。","ENG":"Stimulating her petty pride resulted in quite a film.","TWN":"我不過就稍微刺激一下她那小小的自尊心，結果拍出很不錯的畫面呢！"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"역시 주인님이십니다.","JPN":"さすがご主人様。","ENG":"This is why I respect you, Mistress.","TWN":"真不愧是主人。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"의뢰인께서 이번 일로 배우의 은퇴를 결정한 건 안타까운 일이지만, 은퇴작으로선 부족함이 없겠군요.","JPN":"依頼人が今回のことで女優としての引退を決めたのは残念ですが、引退作品としては十分でしょう。","ENG":"It’s a pity that the client decided to retire as an actress, but I believe this would be more than enough for her last work.","TWN":"雖然很遺憾委託人因為這次的事件，決定不再當演員，但這也算是很完美的告別作。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"그녀석을 계속 따라다니면 더 재미있는 일도 생길 것 같다만…","JPN":"あいつにずっと目をつけていれば、もっと面白いことが起きそうじゃが……","ENG":"I thought we would run into even more interesting events if we kept following her...","TWN":"繼續跟拍她的話，應該還會發生許多有趣的事情…"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"그건 내가 귀찮으니 사양이다.","JPN":"それは妾が面倒くさいから遠慮する。","ENG":"But that would be too much work.","TWN":"但我覺得有點麻煩。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"시종? 간만에 이 몸의 창작욕구도 해소하고 돈도 벌었겠다, 기념으로 간만에 스테이크나…","JPN":"僕？　久々に妾の創作欲を解消してお金も稼いたところで、記念としてステーキを……","ENG":"Servant? Now that I satisfied my desire for creation, and now that we have money, shouldn’t we celebrate with some steak–","TWN":"僕人？難得可以滿足我的創作欲望，還賺到錢，不如就久違地來個牛排慶祝…"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"…음?","JPN":"……うむ？","ENG":"...Hmm?","TWN":"…嗯？"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_PRACTICE","text":{"KOREA":"저기… 안녕하세요?","JPN":"あの……こんにちは。","ENG":"Um... Hello?","TWN":"請問…有人在嗎？"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"의뢰인이냐? 아쉽겠지만 오늘은 의뢰를 받을 생각이 없으니 돌아가도록.","JPN":"依頼人か？　残念じゃが、今日は依頼を受け付ける気はないから帰るのじゃ。","ENG":"Are you here to make a commission? I’m sorry, but we’re closed for the day.","TWN":"是委託人嗎？真可惜，今天不接受委託咧，你回去吧！"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_PRACTICE","text":{"KOREA":"아, 아뇨. 전 그러니까… 감사인사를 드리고 싶어서 왔어요.","JPN":"い、いいえ。私は、えっと……感謝を伝えたくてやってきました。","ENG":"N-No. I just wanted... to thank you.","TWN":"不是的，我…是來道謝的。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"감사인사?","JPN":"感謝を？","ENG":"Thank us?","TWN":"道謝？"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"아, 이렇게 다시 뵙는군요.","JPN":"あっ、またお会いしましたね。","ENG":"Ah, here we meet again.","TWN":"喔，你怎麼會來？"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"응? 너랑 아는 사이냐?","JPN":"うむ？　知り合いか？","ENG":"Huh? Do you know her?","TWN":"嗯？是你認識的喔？"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L33_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"이 분은 의뢰인이 제거를 요청했던 리허설의 경쟁자 중 한 사람입니다.","JPN":"この方は依頼人が排除を要請した、リハーサルのライバルのうち1人です。","ENG":"This is one of the opponents that the client asked us to get rid of.","TWN":"這位是之前那位委託人要求除掉的競爭者之一。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L34_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"제거했다는 것 치곤 멀쩡히 살아있구나? 게다가 너한테 복수도 아니고 감사를 하러 왔다고?","JPN":"排除した割にはちゃんと生きておるな。それに、其方に復讐でもなく感謝をしに来ただと？","ENG":"Get rid of? Well, she looks rather alive. And you said you’re not here to take revenge, but to thank us?","TWN":"不是說要除掉嗎？怎麼還生龍活虎的？而且還不是來找你報仇，而是來道謝的？"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_PRACTICE","text":{"KOREA":"보, 복수라뇨! 그럴 리가요!","JPN":"ふ、復讐だなんて！　そんな！","ENG":"R-revenge? No way!","TWN":"怎…怎麼會！我怎麼可能報仇！"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_PRACTICE","text":{"KOREA":"도마 씨는 유혹의 함교에 출연할 예정인 절 찾아오셔서 다른 작품의 배역을 주선해 주셨어요.","JPN":"ドマさんは誘惑の艦橋に出演する予定だった私を訪ねてきて、他の作品の役を紹介してくれたんです。","ENG":"Mr. Doma came to see me and arranged for me to play a role in a different piece of work.","TWN":"我原本預定要演出誘惑的艦橋，但多馬來找我，還介紹其他的角色給我。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"주선? 넌 반나절 동안 열 명이 넘는 후보들을 상대로 대체 뭘 하고 다닌 거야?","JPN":"役を紹介？　其方は半日で10人を超える候補たちを相手に、いったい何をしていたのじゃ？","ENG":"Arrange? What have you done to all the candidates for only half a day?","TWN":"介紹？你大半天不見，到底是跟那10幾位競爭者幹什麼去啦？"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"후후, 과찬이십니다.","JPN":"フフ、褒めすぎです。","ENG":"Ha ha, I only did what I had to do.","TWN":"呵呵，不敢當。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_PRACTICE","text":{"KOREA":"갑작스럽긴 했지만 그런 큰 작품에 출연한다는 게 부담스럽기도 했고…","JPN":"いきなりだったけど、あんな大作品に出演するのはプレッシャーを感じてましたし……","ENG":"It was a bit sudden, but I felt burdened to take a role of such a popular TV series...","TWN":"突然要演出那麼知名的戲，我覺得很有壓力…"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_PRACTICE","text":{"KOREA":"사실 무투의 달인이자 폭력의 화신인 파벨라 역할을 저처럼 연약하고 평범한 사람이 제대로 소화할 수 있을지 확신도 없었거든요.","JPN":"実は武闘の達人で暴力の化身であるファヴェーラ役を私みたいに弱くて平凡な人がまともにやれるのか、確信もなかったんです。","ENG":"I wasn’t even that certain that a weak and plain person like me could play the role of Fabella, who is the incarnation of violence.","TWN":"而且我這麼普通又柔弱，哪有辦法可以把好鬥又火爆的帕貝拉演好。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"흐음.","JPN":"ふむ。","ENG":"Hmm.","TWN":"嗯哼。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"아무래도 파벨라의 캐릭터를 이해하지 못했던 건 그 의뢰인 뿐이었던 모양이구나.","JPN":"どうやらファヴェーラというキャラクターを理解できていなかったのは、あの依頼人だけだったようじゃのう。","ENG":"I guess it was only the client that didn’t understand Fabella’s character.","TWN":"看來對帕貝拉這個角色有錯誤認知的，就只有那個委託人而已。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_PRACTICE","text":{"KOREA":"그래서, 덕분에 지금은 좋은 작품에서 활동하게 돼서, 도마 씨에겐 감사를 드리고 싶었어요.","JPN":"それで、おかげ様で今ではいい作品に出演することになったので、ドマさんに感謝を伝えたかったんです。","ENG":"Thanks to you, I got a role in a good piece of work. I wanted to thank you, Mr. Doma.","TWN":"因為多馬的介紹我才能演出好的作品，所以我是來向他道謝的。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"후후, 감사는 당신의 재능에 하시면 됩니다. 저에게 하실 필요는 없어요.","JPN":"フフ、あなた自身の才能に感謝してください。私には感謝する必要はありません。","ENG":"Ha ha, give your thanks to your talent. There’s no need to thank me.","TWN":"呵呵，不用客氣，你應該要謝的是你的才能。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"감사라면 이번 의뢰를 주도하신 저희 오너께 드리면 된답니다.","JPN":"感謝なら、今回の依頼をリードなさった我がオーナーにしてください。","ENG":"If you want to thank someone, thank our owner who took the lead of the commission.","TWN":"要謝就謝主導這次委託的負責人吧。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L1_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_PRACTICE","text":{"KOREA":"그… 그런가요?! 그럼 그 오너분은 어디 계시죠?","JPN":"そ……そうなんですか？！　じゃあ、そのオーナーさんはどこに？","ENG":"Is... Is that so?! Then where is the owner?","TWN":"是…是嗎？！那負責人在哪裡呢？"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L2_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"크흠. 이쪽이다.","JPN":"コホン。こっちじゃ。","ENG":"Ahem. I’m right here.","TWN":"咳咳，這裡。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_PRACTICE","text":{"KOREA":"이 사람이… 사무소의 오너?","JPN":"この人が……事務所のオーナー？","ENG":"This person here... is the owner of the private eye?","TWN":"你就是…事務所的負責人？"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_PRACTICE","text":{"KOREA":"앗! 죄송해요! 그러니까 너무 어리… 아니, 젊으셔서 착각했네요.","JPN":"あっ！　すみません！　それが、あまりにも幼い……いや、若くて勘違いしました。","ENG":"I mean, I’m sorry! You’re so little and... no, young that I almost made a mistake.","TWN":"喔！抱歉！你看起來好幼…不是，是看起來太年輕，所以我沒認出來。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_PRACTICE","text":{"KOREA":"아무튼 감사합니다! 오너님 덕분에 배우 활동을 계속 할 수 있게 됐어요!","JPN":"とにかく、ありがとうございます！　オーナーさんのおかげで女優活動を続けることができました！","ENG":"Anyway, thank you! I can persist in my career as an actress thanks to you!","TWN":"總之謝謝你！托你的福，我才能繼續演員之路！"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_PRACTICE","text":{"KOREA":"이 은혜는 평생 잊지 않겠습니다!","JPN":"この恩は一生忘れません！","ENG":"I’ll never forget this!","TWN":"大恩大德永生難忘！"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L8_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"그러냐? 너 좋으라고 한 일은 아니었으니 평생 기억할 필요 없단다.","JPN":"そうか？　其方のためにやったことでもあるまいし、一生覚えている必要はないじゃろう。","ENG":"Is that so? I didn’t intend to do it for your good, so no need to not forget it.","TWN":"是喔？不用啦，我也不是因為喜歡你才這麼做的。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"밥 먹을 시간이니 볼일 끝났으면 돌아가거라.","JPN":"食事の時間じゃ。用が済んだら帰るように。","ENG":"It’s time to eat. You should get going if you’re done.","TWN":"我要吃飯了，你沒事的話就回去吧！"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_PRACTICE","text":{"KOREA":"앗… 네!","JPN":"あっ……はい！","ENG":"Oh! Yes, of course!","TWN":"喔…好！"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_PRACTICE","text":{"KOREA":"그, 그럼 도마 씨… 나중에 제가 또 연락 드릴게요!","JPN":"そ、それじゃ、ドマさん……あとでまた連絡しますね！","ENG":"W-well then, Mr. Doma... I’ll contact you later!","TWN":"那，多馬…我會再跟你聯絡！"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"시종? 지금이 벌써 몇 통째지?","JPN":"僕？　これで何度目じゃ？","ENG":"Servant? How many calls did we get?","TWN":"僕人？這都第幾通啦？"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"지금까지 총 여덟 후보 분들에게 연락을 받았습니다.","JPN":"今まで計8人の候補さんから連絡をもらいました。","ENG":"A total of eight candidates called us so far.","TWN":"目前一共接到8位競爭者的電話。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"다들 주인님의 하해와 같은 은혜에 몸 둘 바를 모르는군요.","JPN":"みんな、ご主人様の暖かい恩恵にとても感動しているようですね。","ENG":"They all don’t know how to react to your kindness.","TWN":"大家都非常感激主人呢。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"그래 그래.","JPN":"よい、よい。","ENG":"Sure, sure.","TWN":"很好很好。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"엎드려 절 받기도 이제 슬슬 지치는구나.","JPN":"お世辞にもそろそろ飽きた。","ENG":"I’m getting tired of fishing for compliments.","TWN":"這種道謝遊戲，我已經開始覺得膩了啦！"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"고작 의뢰의 타깃일 뿐인데, 뭐하러 이렇게 배려해준 거야?","JPN":"依頼のターゲットだっただけなのに、なぜここまで配慮したのじゃ？","ENG":"They were just targets of the commission. Why did you have to be so nice to them?","TWN":"不過就是個委託而已，你有必要這麼大費周章地照顧所有人嗎？"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"어차피 이런 안락한 일상 따위, 연명해봐야 얼마 가지도 못할 텐데.","JPN":"どうせこのような安楽な日常など、延命したとてそう長くは持たぬ。","ENG":"They won’t be able to enjoy this comfortable life for long anyway.","TWN":"反正這種安逸的日子再過也沒多久。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"후후, 그들도 저희와 마찬가지로 피하지 못할 폭풍에 휘말린 입장이지요.","JPN":"フフ、彼らも私たちのように避けられない嵐に巻き込まれた立場です。","ENG":"Ha ha, just like us, they’re caught in a storm they can’t avoid.","TWN":"呵呵，他們也和我們一樣，都被捲入無法避免的暴風之中。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"모두의 미래를 걸고 벌이는 대결이 당장 내일이 된다 하더라도…","JPN":"みんなの未来をかけて繰り広げられる対決が、明日に迫るとしても……","ENG":"Even if the battle for the future comes tomorrow...","TWN":"就算明天就會上演賭上所有人未來的對決…"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"그들에게서 오늘을 살아갈 기회마저 빼앗을 필요는 없으니까요.","JPN":"彼らから今日を生きる機会まで奪う必要はありませんから。","ENG":"We don’t have to deprive them of the opportunity to live today.","TWN":"也沒必要奪走他們今天活命的機會。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"그래. 나도 가끔은 이런 자비를 베푸는 게 나쁘진 않구나.","JPN":"そうじゃな。妾もたまにはこのように慈悲を施すのは悪くないと思うぞ。","ENG":"Yes. Like this, it isn’t bad to have mercy sometimes.","TWN":"好吧，偶爾大發善心也不是什麼壞事。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"그나저나 내 트러플 서로인 스테이크는 언제쯤 도착하느냐?","JPN":"それより、妾のトリュフサーロインステーキはいつごろ来るのじゃ？","ENG":"Anyway, when is my truffle sirloin steak arriving?","TWN":"不過，我的松露牛排怎麼還沒到？"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"죄송하지만, 주인님. 잔고의 여건상 스테이크는 조금 힘들 것 같습니다.","JPN":"申し訳ありませんが、ご主人様。残高上、ステーキは少し無理かと。","ENG":"I’m sorry, Mistress, but we can’t afford to eat steak right now.","TWN":"很抱歉，主人，以公司的財務，要吃牛排可能有點困難。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"아, 또 왜?! 이번엔 의뢰로 돈도 많이 벌었잖아!","JPN":"またなんぞ！？　今回は依頼でお金も稼いだはずじゃ！","ENG":"Again?! We earned lots of money because of the commission!","TWN":"蛤，又為什麼？！這次的委託不是賺到很多錢嗎！"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"의뢰로 받은 선금은 모두 배역 후보들의 리허설에 불참한 위약금으로 쓰였답니다.","JPN":"依頼でもらった前金は全部、役の候補たちがリハーサルに不参加になった際の違約金で使われました。","ENG":"The down payment for the commission was used to pay for all the candidates’ cancellation charges.","TWN":"這次委託收到的訂金，已經全部拿去賠償其他演員無法參與試鏡的違約金。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"그럼 내 회심의 작품은?! 기사에도 오르고 엄청 유명해졌잖아!","JPN":"それでは、妾の会心の力作は！？　記事にもなって有名になったじゃろう！","ENG":"Then what about my piece of work?! It got viral!","TWN":"那我拍的戲呢？！不是有上報，而且還很出名嗎！"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"소속사가 없는 개인의 단편작으론 수익을 창출할 수 없습니다.","JPN":"エージェンシーがない個人の短編作品では、収入を得ることができません。","ENG":"Short movies filmed by individuals without an agency cannot generate revenue.","TWN":"因為不是由製作公司發行的個人影片，所以沒辦法產生收入。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"그래도 이번 기회로 명성을 드높이셨으니 상업영화에 투자 받아 보시는 것도 나쁘지 않겠네요.","JPN":"でもこれを機に世に名声を轟かしたのですから、商業映画の製作に着手し、投資を求めるのもよさそうです。","ENG":"But since you increased your reputation, maybe you can ask for an investment for a commercial film?","TWN":"不過透過這次機會打開知名度後，之後或許會獲得商業片的投資，也是不錯。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"그럼 당장 오늘은?! 내 저녁밥 스테이크는?!","JPN":"では、今日は！？　妾の夕飯のステーキは！？","ENG":"Then what about today?! What about my steak for dinner?!","TWN":"所以現在呢？！我晚餐要吃的牛排呢？！"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"걱정 마시길. 오늘은 이 도마가 햄버그스테이크를 대령하도록 하겠습니다.","JPN":"ご心配なく。今日はこのドマ、ハンバーグをお出ししましょう。","ENG":"No worries. I, Doma, will be happy to serve you hamburger steak.","TWN":"主人請放心，今天的晚餐，就由在下多馬為您準備漢堡排。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"야! 그렇게 말하면서 냉동실 문은 왜 여는 건데!","JPN":"おい！　そう言いつつ勝手に冷凍庫の扉を開くでない！","ENG":"Hey! Why are you opening the fridge as you say that!","TWN":"喂！你說準備漢堡排，那幹嘛開冷凍庫的門！！"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"냉동 싫어! 난 스테이크가 먹고 싶단 말이다!!!","JPN":"冷凍は嫌じゃ！　妾はステーキが食べたい！！！","ENG":"I don’t want frozen meals! I want steak!!!","TWN":"我不要吃冷凍食品啦！人家要吃牛排！！！"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"야! 스테이크 내 놔!!!","JPN":"おい！　ステーキを出せ！！！","ENG":"Hey! Give me my steak!!!","TWN":"喂！給我牛排！！！"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};